 68	async function findRepoRoot(start: string): Promise<string | undefined> {
 69	  let current = resolve(start);
 70	
 71	  while (true) {
 72	    if (await pathExists(join(current, ".git"))) {
 73	      return current;
 74	    }
 75	
 76	    const parent = dirname(current);
 77	    if (parent === current) {
 78	      return undefined;
 79	    }
 80	
 81	    current = parent;
 82	  }
 83	}
