 85	async function packageScriptCandidates(
 86	  searchRoot: string,
 87	  source: string
 88	): Promise<GateSourceCandidates[]> {
 89	  const packageJsonPath = join(searchRoot, "package.json");
 90	  if (!(await pathExists(packageJsonPath))) {
 91	    return [];
 92	  }
 93	
 94	  const packageJson = JSON.parse(await readTextFile(packageJsonPath)) as {
 95	    scripts?: Record<string, string>;
 96	  };
 97	  const scripts = packageJson.scripts ?? {};
 98	
 99	  if (!scripts["green-verify"] && !scripts["verify-all"]) {
100	    return [];
101	  }
102	
103	  return [
104	    {
105	      story: scripts["green-verify"] ? ["bun run green-verify"] : [],
106	      epic: scripts["verify-all"] ? ["bun run verify-all"] : [],
107	      source,
108	    },
109	  ];
110	}
