112	async function docCandidates(
113	  searchRoot: string,
114	  source: string
115	): Promise<GateSourceCandidates[]> {
116	  const candidates: GateSourceCandidates = {
117	    story: [],
118	    epic: [],
119	    source,
120	  };
121	
122	  for (const fileName of ["AGENTS.md", "README.md"]) {
123	    const filePath = join(searchRoot, fileName);
124	    if (!(await pathExists(filePath))) {
125	      continue;
126	    }
127	
128	    const content = await readTextFile(filePath);
129	    for (const match of content.matchAll(/^Story Gate:\s*(.+)$/gim)) {
130	      candidates.story.push(match[1]);
131	    }
132	    for (const match of content.matchAll(/^Epic Gate:\s*(.+)$/gim)) {
133	      candidates.epic.push(match[1]);
134	    }
135	  }
136	
137	  if (candidates.story.length === 0 && candidates.epic.length === 0) {
138	    return [];
139	  }
140	
141	  return [candidates];
142	}
