144	async function ciCandidates(
145	  searchRoot: string,
146	  source: string
147	): Promise<GateSourceCandidates[]> {
148	  const workflowsDir = join(searchRoot, ".github", "workflows");
149	  if (!(await pathExists(workflowsDir))) {
150	    return [];
151	  }
152	
153	  const entries = await readdir(workflowsDir, { withFileTypes: true });
154	  const candidates: GateSourceCandidates = {
155	    story: [],
156	    epic: [],
157	    source,
158	  };
159	
160	  for (const entry of entries) {
161	    if (!entry.isFile() || !entry.name.match(/\.ya?ml$/)) {
162	      continue;
163	    }
164	
165	    const content = await readTextFile(join(workflowsDir, entry.name));
166	    for (const match of content.matchAll(/run:\s*(.+)$/gim)) {
167	      const command = match[1].trim();
168	      if (command.includes("green-verify")) {
169	        candidates.story.push(command);
170	      }
171	      if (command.includes("verify-all")) {
172	        candidates.epic.push(command);
173	      }
174	    }
175	  }
176	
177	  if (candidates.story.length === 0 && candidates.epic.length === 0) {
178	    return [];
179	  }
180	
181	  return [candidates];
182	}
