184	async function localAndRepoRootCandidates(
185	  specPackRoot: string
186	): Promise<GateSourceCandidates[]> {
187	  const repoRoot = await findRepoRoot(specPackRoot);
188	  const searchRoots = [
189	    {
190	      root: specPackRoot,
191	      packageSource: "local package.json scripts",
192	      docSource: "project policy docs",
193	      ciSource: "CI configuration",
194	    },
195	    ...(repoRoot && repoRoot !== specPackRoot
196	      ? [
197	          {
198	            root: repoRoot,
199	            packageSource: "repo-root package.json scripts",
200	            docSource: "repo-root project policy docs",
201	            ciSource: "repo-root CI configuration",
202	          },
203	        ]
204	      : []),
205	  ];
206	
207	  const sourceCandidates: GateSourceCandidates[] = [];
208	  for (const searchRoot of searchRoots) {
209	    sourceCandidates.push(
210	      ...(await packageScriptCandidates(searchRoot.root, searchRoot.packageSource))
211	    );
212	    sourceCandidates.push(
213	      ...(await docCandidates(searchRoot.root, searchRoot.docSource))
214	    );
215	    sourceCandidates.push(
216	      ...(await ciCandidates(searchRoot.root, searchRoot.ciSource))
217	    );
218	  }
219	
220	  return sourceCandidates;
221	}
