223	export async function resolveVerificationGates(input: {
224	  specPackRoot: string;
225	  explicitStoryGate?: string;
226	  explicitEpicGate?: string;
227	}): Promise<GateDiscoveryResult> {
228	  const specPackRoot = resolve(input.specPackRoot);
229	  const sourceCandidates = await localAndRepoRootCandidates(specPackRoot);
230	  const storyResolution = resolveGateValue({
231	    explicitValue: input.explicitStoryGate,
232	    sourceCandidates,
233	    gate: "story",
234	  });
235	  const epicResolution = resolveGateValue({
236	    explicitValue: input.explicitEpicGate,
237	    sourceCandidates,
238	    gate: "epic",
239	  });
240	
241	  if (
242	    storyResolution.ambiguous ||
243	    epicResolution.ambiguous ||
244	    !storyResolution.value ||
245	    !epicResolution.value ||
246	    !storyResolution.source ||
247	    !epicResolution.source
248	  ) {
249	    return {
250	      status: "needs-user-decision",
251	      errors: [
252	        {
253	          code: "VERIFICATION_GATE_UNRESOLVED",
254	          message: "Verification gate policy is ambiguous",
255	          detail:
256	            "Provide --story-gate and --epic-gate explicitly or clarify the project policy.",
257	        },
258	      ],
259	      notes: [],
260	    };
261	  }
262	
263	  return {
264	    status: "ready",
265	    verificationGates: {
266	      storyGate: storyResolution.value,
267	      epicGate: epicResolution.value,
268	      storyGateSource: storyResolution.source,
269	      epicGateSource: epicResolution.source,
270	    },
271	    errors: [],
272	    notes: [],
273	  };
274	}

