 83	export function resolveRunConfigPath(
 84	  specPackRoot: string,
 85	  configPath?: string
 86	): string {
 87	  if (!configPath) {
 88	    return resolve(specPackRoot, RUN_CONFIG_FILE_NAME);
 89	  }
 90	
 91	  return resolve(specPackRoot, configPath);
