 93	
 94	function formatConfigLoadError(error: unknown, resolvedPath: string): string {
 95	  if (error instanceof z.ZodError) {
 96	    const issues = error.issues
 97	      .map((issue) => {
 98	        const path = issue.path.length > 0 ? issue.path.join(".") : "<root>";
 99	        return `${path}: ${issue.message}`;
100	      })
101	      .join("; ");
102	    return `Run-config validation failed for ${resolvedPath}: ${issues}`;
103	  }
104	
105	  if (error instanceof Error) {
106	    return `Run-config load failed for ${resolvedPath}: ${error.message}`;
107	  }
108	
109	  return `Run-config load failed for ${resolvedPath}: ${String(error)}`;
110	}
