112	export async function loadRunConfig(input: {
113	  specPackRoot: string;
114	  configPath?: string;
115	}): Promise<ImplRunConfig> {
116	  const resolvedPath = resolveRunConfigPath(input.specPackRoot, input.configPath);
117	  try {
118	    const { config } = await loadConfig({
119	      cwd: resolve(input.specPackRoot),
120	      configFile: relative(resolve(input.specPackRoot), resolvedPath),
121	      configFileRequired: true,
122	      rcFile: false,
123	      globalRc: false,
124	      packageJson: false,
125	      dotenv: false,
126	      extend: false,
127	    });
128	
129	    return implRunConfigSchema.parse(config);
130	  } catch (error) {
131	    throw new ConfigLoadError(formatConfigLoadError(error, resolvedPath), {
132	      cause: error,
133	    });
134	  }
135	}

