287	async function executePrompt(input: {
288	  provider: ProviderName;
289	  specPackRoot: string;
290	  model: string;
291	  reasoningEffort: string;
292	  prompt: string;
293	  resumeSessionId?: string;
294	  env?: Record<string, string | undefined>;
295	}): Promise<PromptExecutionSuccess | PromptExecutionFailure> {
296	  const adapter = createProviderAdapter(input.provider, {
297	    env: input.env,
298	  });
299	  const execution = await adapter.execute({
300	    prompt: input.prompt,
301	    cwd: input.specPackRoot,
302	    model: input.model,
303	    reasoningEffort: input.reasoningEffort,
304	    resumeSessionId: input.resumeSessionId,
305	    timeoutMs: 30_000,
306	    resultSchema: providerPayloadSchema,
307	  });
308	
309	  if (execution.exitCode !== 0) {
310	    return {
311	      outcome: "blocked" as const,
312	      errors: [
313	        executionFailureError({
314	          provider: input.provider,
315	          stderr: execution.stderr,
316	          errorCode: execution.errorCode,
317	        }),
318	      ],
319	    };
320	  }
321	
322	  if (execution.parseError || !execution.parsedResult) {
323	    return {
324	      outcome: "blocked" as const,
325	      errors: [
326	        blockedError(
327	          "PROVIDER_OUTPUT_INVALID",
328	          `Provider output was invalid for ${input.provider}.`,
329	          execution.parseError
330	        ),
331	      ],
332	    };
333	  }
334	
335	  const sessionId = execution.sessionId ?? input.resumeSessionId;
336	  if (!sessionId) {
337	    return {
338	      outcome: "blocked" as const,
339	      errors: [
340	        blockedError(
341	          "CONTINUATION_HANDLE_INVALID",
342	          `Provider ${input.provider} did not return a session id for a retained implementor workflow.`
343	        ),
344	      ],
345	    };
346	  }
347	
348	  return {
349	    outcome: execution.parsedResult.outcome,
350	    sessionId,
351	    payload: execution.parsedResult,
352	  };
353	}
