404	export async function validateContinuationHandle(input: {
405	  specPackRoot: string;
406	  storyId: string;
407	  provider: string;
408	  sessionId: string;
409	}): Promise<CliError | null> {
410	  const provider = providerIdSchema.safeParse(input.provider);
411	  if (!provider.success) {
412	    return blockedError(
413	      "CONTINUATION_HANDLE_INVALID",
414	      `Provider '${input.provider}' is not a valid continuation provider.`
415	    );
416	  }
417	
418	  if (provider.data === "copilot") {
419	    return blockedError(
420	      "CONTINUATION_HANDLE_INVALID",
421	      "Provider 'copilot' cannot be used for retained story_implementor continuation sessions."
422	    );
423	  }
424	
425	  const owner = await resolveContinuationOwner({
426	    specPackRoot: input.specPackRoot,
427	    provider: provider.data,
428	    sessionId: input.sessionId,
429	  });
430	  if (owner === input.storyId) {
431	    return null;
432	  }
433	
434	  if (owner) {
435	    return blockedError(
436	      "CONTINUATION_HANDLE_INVALID",
437	      `Continuation handle ${input.sessionId} belongs to '${owner}', not '${input.storyId}'.`
438	    );
439	  }
440	
441	  return blockedError(
442	    "CONTINUATION_HANDLE_INVALID",
443	    `Continuation handle ${input.sessionId} was not found for story '${input.storyId}'.`
444	  );
445	}
