311	export async function runStoryVerify(input: {
312	  specPackRoot: string;
313	  storyId: string;
314	  configPath?: string;
315	  env?: Record<string, string | undefined>;
316	}): Promise<StoryVerifyWorkflowResult> {
317	  const context = await prepareStoryVerifyContext(input);
318	  if ("errors" in context) {
319	    return {
320	      outcome: "block",
321	      errors: context.errors,
322	      warnings: [],
323	    };
324	  }
325	
326	  try {
327	    const executions = await Promise.all(
328	      context.verifiers.map(async (verifier) => {
329	        const prompt = await assemblePrompt({
330	          role: "story_verifier",
331	          verifierLabel: verifier.label,
332	          storyId: context.story.id,
333	          storyTitle: context.story.title,
334	          storyPath: context.story.path,
335	          techDesignPath: context.paths.techDesignPath,
336	          techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
337	          testPlanPath: context.paths.testPlanPath,
338	          gateCommands: context.gateCommands,
339	          verifierPromptInsertPath: context.verifierPromptInsertPath,
340	        });
341	        const execution = await executeVerifier({
342	          provider: verifier.provider,
343	          specPackRoot: context.specPackRoot,
344	          model: verifier.model,
345	          reasoningEffort: verifier.reasoningEffort,
346	          prompt: prompt.prompt,
347	          env: input.env,
348	        });
349	
350	        if ("errors" in execution) {
351	          return execution;
352	        }
353	
354	        return {
355	          result: buildVerifierResult({
356	            verifier,
357	            story: context.story,
358	            payload: execution.payload,
359	          }),
360	        };
361	      })
362	    );
363	
364	    const errors = executions.flatMap((execution) =>
365	      "errors" in execution ? execution.errors : []
366	    );
367	    const verifierResults = executions.flatMap((execution) =>
368	      "result" in execution ? [execution.result] : []
369	    );
370	    if (errors.length > 0) {
371	      return {
372	        outcome: "block",
373	        result:
374	          verifierResults.length > 0
375	            ? buildVerifierBatchResult({
376	                outcome: "block",
377	                story: context.story,
378	                verifierResults,
379	              })
380	            : undefined,
381	        errors,
382	        warnings: [],
383	      };
384	    }
385	
386	    const outcome = aggregateVerifierBatchOutcome(verifierResults);
387	
388	    return {
389	      outcome,
390	      result: buildVerifierBatchResult({
391	        outcome,
392	        story: context.story,
393	        verifierResults,
394	      }),
395	      errors: [],
396	      warnings: [],
397	    };
398	  } catch (error) {
399	    const failure = promptInsertFailure(error);
400	    if (failure) {
401	      return failure;
402	    }
403	
404	    throw error;
405	  }
406	}

