292	async function loadPublicInsert(
293	  path: string | undefined
294	): Promise<{ assetId?: string; content?: string }> {
295	  if (!path || !(await pathExists(path))) {
296	    return {};
297	  }
298	
299	  const file = Bun.file(path);
300	  if (file.size > MAX_PUBLIC_INSERT_BYTES) {
301	    throw new PromptInsertError(
302	      `Public prompt insert exceeds ${MAX_PUBLIC_INSERT_BYTES} bytes: ${path}`
303	    );
304	  }
305	
306	  try {
307	    return {
308	      assetId: basename(path),
309	      content: await readTextFile(path),
310	    };
311	  } catch (error) {
312	    throw new PromptInsertError(
313	      `Public prompt insert could not be read: ${path}${
314	        error instanceof Error ? ` (${error.message})` : ""
315	      }`
316	    );
317	  }
318	}
