321	  // Keep the size/readability guard structural so any future role-specific insert
322	  // path still passes through the same validation boundary.
323	  if (
324	    "implementationPromptInsertPath" in input &&
325	    typeof input.implementationPromptInsertPath === "string"
326	  ) {
327	    return input.implementationPromptInsertPath;
328	  }
329	
330	  if (
331	    "verifierPromptInsertPath" in input &&
332	    typeof input.verifierPromptInsertPath === "string"
333	  ) {
334	    return input.verifierPromptInsertPath;
335	  }
336	
337	  return undefined;
338	}
