356	export async function assemblePrompt(
357	  input: PromptAssemblyInput
358	): Promise<PromptAssemblyResult> {
359	  const assets = getEmbeddedPromptAssets();
360	  const basePromptId = basePromptIdForRole(input.role);
361	  const snippetIds = snippetIdsForInput(input);
362	  const values = runtimeValues(input);
363	  const publicInsert = await loadPublicInsert(publicInsertPathForInput(input));
364	
365	  const sections = [
366	    interpolateTemplate(assets.base[basePromptId], values),
367	    ...snippetIds.map((snippetId) =>
368	      interpolateTemplate(assets.snippets[snippetId], values)
369	    ),
370	    selfReviewSection(input),
371	    followupSection(input),
372	    publicInsert.content ? publicInsert.content.trimEnd() : "",
373	  ].filter((section) => section.length > 0);
374	
375	  return {
376	    prompt: `${sections.join("\n\n")}\n`,
377	    basePromptId,
378	    snippetIds,
379	    publicInsertIds: publicInsert.assetId ? [publicInsert.assetId] : [],
380	  };

