 59	function executableForHarness(harness: "claude-code" | SecondaryHarness): string | null {
 60	  switch (harness) {
 61	    case "claude-code":
 62	      return "claude";
 63	    case "codex":
 64	      return "codex";
 65	    case "copilot":
 66	      return "copilot";
 67	    case "none":
 68	      return null;
 69	  }
 70	}
 71	
 72	function authCommandForHarness(
 73	  harness: "claude-code" | SecondaryHarness
 74	): string[] | undefined {
 75	  switch (harness) {
 76	    case "claude-code":
 77	    case "codex":
 78	    case "copilot":
 79	      return ["auth", "status"];
 80	    case "none":
 81	      return undefined;
 82	  }
 83	}
 84	
 85	function failureNotes(result: {
 86	  stderr: string;
 87	  timedOut?: boolean;
 88	  code?: string | number;
 89	}, executable: string, step: string): string[] {
 90	  if (result.stderr) {
 91	    return [result.stderr];
 92	  }
 93	
 94	  if (result.timedOut) {
 95	    return [`${executable} ${step} timed out`];
 96	  }
 97	
 98	  return [`Unable to execute ${executable} ${step}`];
 99	}
