101	function looksLikeMissingAuthCommand(stderr: string): boolean {
102	  const lower = stderr.toLowerCase();
103	  return lower.includes("unexpected auth invocation");
104	}
105	
106	function looksLikeExplicitAuthFailure(stderr: string): boolean {
107	  const lower = stderr.toLowerCase();
108	  return (
109	    lower.includes("missing") ||
110	    lower.includes("not logged in") ||
111	    lower.includes("unauth") ||
112	    lower.includes("sign in")
113	  );
114	}
