116	async function checkHarnessAvailability(input: {
117	  harness: "claude-code" | SecondaryHarness;
118	  cwd: string;
119	  env?: Record<string, string | undefined>;
120	  timeoutMs: number;
121	}): Promise<HarnessAvailability> {
122	  const executable = executableForHarness(input.harness);
123	  if (!executable) {
124	    return {
125	      harness: "none",
126	      available: true,
127	      tier: "binary-present",
128	      authStatus: "unknown",
129	      notes: [],
130	    };
131	  }
132	
133	  const version = await runCommand({
134	    file: executable,
135	    args: ["--version"],
136	    cwd: input.cwd,
137	    env: input.env,
138	    timeoutMs: input.timeoutMs,
139	  });
140	  if (!version.success) {
141	    return {
142	      harness: input.harness,
143	      available: false,
144	      tier: "unavailable",
145	      authStatus: version.code === "ENOENT" ? "missing" : "unknown",
146	      notes: failureNotes(version, executable, "--version"),
147	    };
148	  }
149	
150	  const authCommand = authCommandForHarness(input.harness);
151	  if (!authCommand) {
152	    return {
153	      harness: input.harness,
154	      available: true,
155	      tier: "binary-present",
156	      version: version.stdout,
157	      authStatus: "unknown",
158	      notes: [
159	        `No non-mutating auth status command is available for ${input.harness}.`,
160	      ],
161	    };
162	  }
163	
164	  const auth = await runCommand({
165	    file: executable,
166	    args: authCommand,
167	    cwd: input.cwd,
168	    env: input.env,
169	    timeoutMs: input.timeoutMs,
170	  });
171	  if (!auth.success) {
172	    if (looksLikeMissingAuthCommand(auth.stderr)) {
173	      return {
174	        harness: input.harness,
175	        available: true,
176	        tier: "binary-present",
177	        version: version.stdout,
178	        authStatus: "unknown",
179	        notes: failureNotes(auth, executable, "auth status"),
180	      };
181	    }
182	
183	    if (!auth.timedOut && !looksLikeExplicitAuthFailure(auth.stderr)) {
184	      return {
185	        harness: input.harness,
186	        available: true,
187	        tier: "auth-unknown",
188	        version: version.stdout,
189	        authStatus: "unknown",
190	        notes: failureNotes(auth, executable, "auth status"),
191	      };
192	    }
193	
194	    return {
195	      harness: input.harness,
196	      available: false,
197	      tier: "unavailable",
198	      version: version.stdout,
199	      authStatus: looksLikeExplicitAuthFailure(auth.stderr) ? "missing" : "unknown",
200	      notes: failureNotes(auth, executable, "auth status"),
201	    };
202	  }
203	
204	  return {
205	    harness: input.harness,
206	    available: true,
207	    tier: "authenticated-known",
208	    version: version.stdout,
209	    authStatus: "authenticated",
210	    notes: auth.stdout ? [auth.stdout] : [],
211	  };
212	}
