231	export async function resolveProviderMatrix(input: {
232	  specPackRoot: string;
233	  config: ImplRunConfig;
234	  env?: Record<string, string | undefined>;
235	  timeoutMs?: number;
236	}): Promise<ProviderMatrix> {
237	  const cwd = (await resolveGitRepoRoot(input.specPackRoot)) ?? input.specPackRoot;
238	  const timeoutMs = input.timeoutMs ?? DEFAULT_PROVIDER_CHECK_TIMEOUT_MS;
239	  const primary = await checkHarnessAvailability({
240	    harness: "claude-code",
241	    cwd,
242	    env: input.env,
243	    timeoutMs,
244	  });
245	  const secondary: HarnessAvailability[] = [];
246	
247	  for (const harness of requestedSecondaryHarnesses(input.config)) {
248	    secondary.push(
249	      await checkHarnessAvailability({
250	        harness,
251	        cwd,
252	        env: input.env,
253	        timeoutMs,
254	      })
255	    );
256	  }
257	
258	  return {
259	    primary,
260	    secondary,
261	  };
262	}

