415	export function statusForOutcome(outcome: string): CliStatus {
416	  switch (outcome) {
417	    case "ready":
418	    case "ready-for-verification":
419	    case "needs-followup-fix":
420	    case "pass":
421	    case "revise":
422	    case "cleaned":
423	    case "needs-more-cleanup":
424	    case "ready-for-closeout":
425	    case "needs-fixes":
426	    case "needs-more-routing":
427	    case "needs-more-verification":
428	      return "ok";
429	    case "block":
430	      return "blocked";
431	    case "needs-user-decision":
432	    case "needs-human-ruling":
433	      return "needs-user-decision";
434	    case "blocked":
435	      return "blocked";
436	    default:
437	      return "error";
438	  }
439	}
440	
441	const zeroExitOutcomes = new Set([
442	  "ready",
443	  "ready-for-verification",
444	  "pass",
445	  "cleaned",
446	  "ready-for-closeout",
447	]);
448	
449	export function exitCodeForStatus(status: CliStatus, outcome?: string): number {
450	  switch (status) {
451	    case "ok":
452	      return outcome && !zeroExitOutcomes.has(outcome) ? 2 : 0;
453	    case "needs-user-decision":
454	      return 2;
455	    case "blocked":
456	      return 3;
457	    case "error":
458	    default:
459	      return 1;
460	  }
461	}
