463	export function cliResultEnvelopeSchema<T extends z.ZodTypeAny>(resultSchema: T) {
464	  return z
465	    .object({
466	      command: z.string().min(1),
467	      version: z.literal(1),
468	      status: cliStatusSchema,
469	      outcome: z.string().min(1),
470	      result: resultSchema.optional(),
471	      errors: z.array(cliErrorSchema),
472	      warnings: z.array(z.string()),
473	      artifacts: z.array(cliArtifactRefSchema),
474	      startedAt: z.string().min(1),
475	      finishedAt: z.string().min(1),
476	    })
477	    .superRefine((value, ctx) => {
478	      const expectedStatus = statusForOutcome(value.outcome);
479	      if (expectedStatus !== value.status) {
480	        ctx.addIssue({
481	          code: z.ZodIssueCode.custom,
482	          message: `Envelope status '${value.status}' does not match outcome '${value.outcome}'`,
483	          path: ["status"],
484	        });
485	      }
486	
487	      if (
488	        value.result &&
489	        typeof value.result === "object" &&
490	        "outcome" in value.result &&
491	        typeof value.result.outcome === "string" &&
492	        value.result.outcome !== value.outcome
493	      ) {
494	        ctx.addIssue({
495	          code: z.ZodIssueCode.custom,
496	          message: `Envelope outcome '${value.outcome}' does not match result outcome '${value.result.outcome}'`,
497	          path: ["outcome"],
498	        });
499	      }
500	    });
501	}
