503	export function createResultEnvelope<T>(input: {
504	  command: string;
505	  outcome: string;
506	  result?: T;
507	  errors?: CliError[];
508	  warnings?: string[];
509	  artifacts?: CliArtifactRef[];
510	  startedAt: string;
511	  finishedAt: string;
512	}) {
513	  return {
514	    command: input.command,
515	    version: 1 as const,
516	    status: statusForOutcome(input.outcome),
517	    outcome: input.outcome,
518	    result: input.result,
519	    errors: input.errors ?? [],
520	    warnings: input.warnings ?? [],
521	    artifacts: input.artifacts ?? [],
522	    startedAt: input.startedAt,
523	    finishedAt: input.finishedAt,
524	  };
525	}

