 15	async function writeProviderBinary(params: {
 16	  dir: string;
 17	  name: string;
 18	  version: string;
 19	  authStatus?: "authenticated" | "missing";
 20	  authBehavior?: "normal" | "timeout" | "unknown" | "unsupported";
 21	  captureCwdPath?: string;
 22	  failureStderr?: string;
 23	  authFailureStderr?: string;
 24	}) {
 25	  const authStatus = params.authStatus ?? "authenticated";
 26	  const scriptPath = join(params.dir, params.name);
 27	  const script = [
 28	    "#!/bin/sh",
 29	    params.captureCwdPath
 30	      ? `printf '%s' \"$PWD\" > "${params.captureCwdPath}"`
 31	      : "",
 32	    'if [ "$1" = "--version" ]; then',
 33	    params.failureStderr
 34	      ? `  echo "${params.failureStderr}" >&2`
 35	      : "",
 36	    `  echo "${params.version}"`,
 37	    "  exit 0",
 38	    "fi",
 39	    'if [ "$1" = "auth" ] && [ "$2" = "status" ]; then',
 40	    params.authBehavior === "timeout"
 41	      ? "  sleep 2"
 42	      : params.authBehavior === "unsupported"
 43	        ? `  echo "${params.authFailureStderr ?? "unexpected auth invocation"}" >&2`
 44	      : params.authBehavior === "unknown"
 45	        ? `  echo "${params.authFailureStderr ?? "transient provider failure"}" >&2`
 46	        : authStatus === "authenticated"
 47	          ? '  echo "authenticated"'
 48	          : '  echo "missing" >&2',
 49	    params.authBehavior === "timeout"
 50	      ? "  exit 0"
 51	      : params.authBehavior === "unsupported"
 52	        ? "  exit 1"
 53	      : params.authBehavior === "unknown"
 54	        ? "  exit 70"
 55	        : authStatus === "authenticated"
 56	          ? "  exit 0"
 57	          : "  exit 1",
 58	    "fi",
 59	    'echo "unexpected invocation" >&2',
 60	    "exit 1",
 61	    "",
 62	  ].join("\n");
 63	  await writeTextFile(scriptPath, script);
 64	  await chmod(scriptPath, 0o755);
 65	}
