 29	  if (companionFiles.length === 0) {
 30	    return {
 31	      techDesignShape: "two-file",
 32	      companionPaths: [],
 33	      blockers: [],
 34	    };
 35	  }
 36	
 37	  if (companionFiles.length === 2) {
 38	    return {
 39	      techDesignShape: "four-file",
 40	      companionPaths: companionFiles,
 41	      blockers: [],
 42	    };
 43	  }
 44	
 45	  return {
 46	    techDesignShape: "two-file",
 47	    companionPaths: [],
 48	    blockers: [
 49	      "Invalid tech-design companion layout: expected exactly two additional tech-design-*.md companion files for the four-file configuration",
 50	    ],
