 54	export async function inspectSpecPack(specPackRoot: string): Promise<InspectResult> {
 55	  const resolvedRoot = resolve(specPackRoot);
 56	  const epicPath = join(resolvedRoot, "epic.md");
 57	  const techDesignPath = join(resolvedRoot, "tech-design.md");
 58	  const testPlanPath = join(resolvedRoot, "test-plan.md");
 59	  const storiesDir = join(resolvedRoot, "stories");
 60	  const storiesFile = join(resolvedRoot, "stories.md");
 61	  const blockers: string[] = [];
 62	  const notes: string[] = [];
 63	
 64	  const repoRoot = await resolveGitRepoRoot(resolvedRoot);
 65	  if (!repoRoot) {
 66	    blockers.push(`Spec-pack root is not inside a git repo: ${resolvedRoot}`);
 67	  }
 68	
 69	  if (!(await pathExists(epicPath))) {
 70	    blockers.push("Missing required artifact: epic.md");
 71	  }
 72	
 73	  if (!(await pathExists(techDesignPath))) {
 74	    blockers.push("Missing required artifact: tech-design.md");
 75	  }
 76	
 77	  if (!(await pathExists(testPlanPath))) {
 78	    blockers.push("Missing required artifact: test-plan.md");
 79	  }
 80	
 81	  const storiesDirExists = await pathIsDirectory(storiesDir);
 82	  if (!storiesDirExists && (await pathExists(storiesFile))) {
 83	    blockers.push("Expected stories/ directory but found stories.md");
 84	  } else if (!storiesDirExists) {
 85	    blockers.push("Missing required artifact: stories/");
 86	  }
 87	
 88	  const rootEntries = await readdir(resolvedRoot);
 89	  const techDesignArtifacts = resolveTechDesignArtifacts(rootEntries);
 90	  blockers.push(...techDesignArtifacts.blockers);
 91	
 92	  const storyOrder = storiesDirExists
 93	    ? await resolveStoryOrder(storiesDir)
 94	    : { status: "ready" as const, stories: [], notes: [] };
 95	  notes.push(...storyOrder.notes);
 96	  const implInsertPath = join(
 97	    resolvedRoot,
 98	    "custom-story-impl-prompt-insert.md"
 99	  );
100	  const verifierInsertPath = join(
101	    resolvedRoot,
102	    "custom-story-verifier-prompt-insert.md"
103	  );
104	  const implInsertExists = await pathExists(implInsertPath);
105	  const verifierInsertExists = await pathExists(verifierInsertPath);
106	
107	  if (implInsertExists && !(await pathReadable(implInsertPath))) {
108	    blockers.push(
109	      "Unreadable prompt insert: custom-story-impl-prompt-insert.md"
110	    );
111	  }
112	
113	  if (verifierInsertExists && !(await pathReadable(verifierInsertPath))) {
114	    blockers.push(
115	      "Unreadable prompt insert: custom-story-verifier-prompt-insert.md"
116	    );
117	  }
118	
119	  const status =
120	    blockers.length > 0
121	      ? "blocked"
122	      : storyOrder.status === "needs-user-decision"
123	        ? "needs-user-decision"
124	        : "ready";
125	
126	  const result: InspectResult = {
127	    status,
128	    specPackRoot: resolvedRoot,
129	    techDesignShape: techDesignArtifacts.techDesignShape,
130	    artifacts: {
131	      epicPath,
132	      techDesignPath,
133	      techDesignCompanionPaths: techDesignArtifacts.companionPaths.map((file) =>
134	        join(resolvedRoot, file)
135	      ),
136	      testPlanPath,
137	      storiesDir,
138	    },
139	    stories: storyOrder.stories,
140	    inserts: {
141	      customStoryImplPromptInsert: implInsertExists ? "present" : "absent",
142	      customStoryVerifierPromptInsert: verifierInsertExists
143	        ? "present"
144	        : "absent",
145	    },
146	    blockers,
147	    notes,
148	  };
149	
150	  return inspectResultSchema.parse(result);
151	}

