 63	}): CliError {
 64	  if (input.errorCode === "ENOENT") {
 65	    return blockedError(
 66	      "PROVIDER_UNAVAILABLE",
 67	      `Provider executable is unavailable for ${input.provider}.`,
 68	      input.stderr
 69	    );
 70	  }
 71	
 72	  return blockedError(
