172	    resultId: randomUUID(),
173	    outcome: input.payload.outcome,
174	    cleanupBatchPath: input.cleanupBatchPath,
175	    filesChanged: input.payload.filesChanged,
176	    changeSummary: input.payload.changeSummary,
177	    gatesRun: input.payload.gatesRun,
